            if len(subtree) < 2:
                continue

            # Find the root of the subtree
            for root in subtree:
                if all(neighbor in subtree for neighbor in graph[root]):
                    break

            # Check if the subset forms a connected subtree
            visited = set()
            def is_connected(node):
